177	/// Write Batch
178	///
179	/// A [`WBatch`] is a non-expandable and contiguous region of memory
180	/// that is used to serialize [`TransportMessage`] and [`NetworkMessage`].
181	///
182	/// [`TransportMessage`] are always serialized on the batch as they are, while
183	/// [`NetworkMessage`] are always serializaed on the batch as part of a [`TransportMessage`]
184	/// [TransportMessage] Frame. Reliable and Best Effort Frames can be interleaved on the same
185	/// [`WBatch`] as long as they fit in the remaining buffer capacity.
186	///
187	/// In the serialized form, the [`WBatch`] always contains one or more
188	/// [`TransportMessage`]. In the particular case of [`TransportMessage`] Frame,
189	/// its payload is either (i) one or more complete [`NetworkMessage`] or (ii) a fragment of a
190	/// a [`NetworkMessage`].
191	///
192	/// As an example, the content of the [`WBatch`] in memory could be:
193	///
194	/// | Keep Alive | Frame Reliable\<Zenoh Message, Zenoh Message\> | Frame Best Effort\<Zenoh Message Fragment\> |
195	///
196	/// [`NetworkMessage`]: zenoh_protocol::network::NetworkMessage
197	#[derive(Clone, Debug)]
198	pub struct WBatch {
199	    // The buffer to perform the batching on
200	    pub buffer: BBuf,
201	    // The batch codec
202	    pub codec: Zenoh080Batch,
203	    // It contains 1 byte as additional header, e.g. to signal the batch is compressed
204	    pub config: BatchConfig,
205	    // Statistics related to this batch
206	    #[cfg(feature = "stats")]
207	    pub stats: WBatchStats,
208	    // an ephemeral batch will not be recycled in the pipeline
209	    // it can be used to push a stop fragment when no batch are available
210	    pub ephemeral: bool,
211	}
212	
213	impl WBatch {
214	    pub fn new(config: BatchConfig) -> Self {
215	        let mut batch = Self {
216	            buffer: BBuf::with_capacity(config.mtu as usize),
217	            codec: Zenoh080Batch::new(),
218	            config,
219	            ephemeral: false,
220	            #[cfg(feature = "stats")]
221	            stats: WBatchStats::default(),
222	        };
223	
224	        // Bring the batch in a clear state
225	        batch.clear();
226	
227	        batch
228	    }
229	
230	    pub fn new_ephemeral(config: BatchConfig) -> Self {
231	        Self {
232	            ephemeral: true,
233	            ..Self::new(config)
234	        }
235	    }
236	
237	    pub fn is_ephemeral(&self) -> bool {
238	        self.ephemeral
239	    }
240	
241	    /// Verify that the [`WBatch`] has no serialized bytes.
242	    #[inline(always)]
243	    pub fn is_empty(&self) -> bool {
244	        self.len() == 0
245	    }
246	
247	    /// Get the total number of bytes that have been serialized on the [`WBatch`].
248	    #[inline(always)]
249	    pub fn len(&self) -> BatchSize {
250	        let (_l, _h, p) = Self::split(self.buffer.as_slice(), &self.config);
251	        p.len() as BatchSize
252	    }
253	
254	    /// Clear the [`WBatch`] memory buffer and related internal state.
255	    #[inline(always)]
256	    pub fn clear(&mut self) {
257	        self.buffer.clear();
258	        self.codec.clear();
259	        #[cfg(feature = "stats")]
260	        {
261	            self.stats.clear();
262	        }
263	        Self::init(&mut self.buffer, &self.config);
264	    }
265	
266	    /// Get a `&[u8]` to access the internal memory buffer, usually for transmitting it on the network.
267	    #[inline(always)]
268	    pub fn as_slice(&self) -> &[u8] {
269	        self.buffer.as_slice()
270	    }
271	
272	    fn init(buffer: &mut BBuf, config: &BatchConfig) {
273	        let writer = buffer.writer();
274	        if config.is_streamed {
275	            let _ = writer.write_exact(&BatchSize::MIN.to_be_bytes());
276	        }
277	        if let Some(h) = config.header() {
278	            let _ = writer.write_u8(h.as_u8());
279	        }
280	    }
281	
282	    // Split (length, header, payload) internal buffer slice
283	    #[inline(always)]
284	    fn split<'a>(buffer: &'a [u8], config: &BatchConfig) -> (&'a [u8], &'a [u8], &'a [u8]) {
285	        zsplit!(buffer, config)
286	    }
287	
288	    // Split (length, header, payload) internal buffer slice
289	    #[inline(always)]
290	    fn split_mut<'a>(
291	        buffer: &'a mut [u8],
292	        config: &BatchConfig,
293	    ) -> (&'a mut [u8], &'a mut [u8], &'a mut [u8]) {
294	        zsplit_mut!(buffer, config)
295	    }
296	
297	    pub fn finalize(&mut self, mut buffer: Option<&mut BBuf>) -> ZResult<Finalize> {
298	        #[allow(unused_mut)]
299	        let mut res = Finalize::Batch;
300	
301	        #[cfg(feature = "transport_compression")]
302	        if let Some(h) = self.config.header() {
303	            if h.is_compression() {
304	                let buffer = buffer
305	                    .as_mut()
306	                    .ok_or_else(|| zerror!("Support buffer not provided"))?;
307	                res = self.compress(buffer)?;
308	            }
309	        }
310	
311	        if self.config.is_streamed {
312	            let buff = match res {
313	                Finalize::Batch => self.buffer.as_mut_slice(),
314	                Finalize::Buffer => buffer
315	                    .as_mut()
316	                    .ok_or_else(|| zerror!("Support buffer not provided"))?
317	                    .as_mut_slice(),
318	            };
319	            let (length, header, payload) = Self::split_mut(buff, &self.config);
320	            let len: BatchSize = (header.len() as BatchSize) + (payload.len() as BatchSize);
321	            length.copy_from_slice(&len.to_le_bytes());
322	        }
323	
324	        Ok(res)
325	    }
326	
327	    #[cfg(feature = "transport_compression")]
328	    fn compress(&mut self, support: &mut BBuf) -> ZResult<Finalize> {
329	        // Write the initial bytes for the batch
330	        support.clear();
331	        Self::init(support, &self.config);
332	
333	        // Compress the actual content
334	        let (_length, _header, payload) = Self::split(self.buffer.as_slice(), &self.config);
335	        let writer = support.writer();
336	        // SAFETY: assertion ensures `with_slot` precondition
337	        unsafe {
338	            writer.with_slot(writer.remaining(), |b| {
339	                let len = lz4_flex::block::compress_into(payload, b).unwrap_or(0);
340	                assert!(len <= b.len());
341	                len
342	            })
343	        }
344	        .map_err(|_| zerror!("Compression error"))?;
345	
346	        // Verify whether the resulting compressed data is smaller than the initial input
347	        if support.len() < self.buffer.len() {
348	            Ok(Finalize::Buffer)
349	        } else {
350	            // Keep the original uncompressed buffer and unset the compression flag from the header
351	            let (_l, h, _p) = Self::split_mut(self.buffer.as_mut_slice(), &self.config);
352	            let h = h.first_mut().ok_or_else(|| zerror!("Empty BatchHeader"))?;
353	            *h &= !BatchHeader::COMPRESSION;
354	            Ok(Finalize::Batch)
355	        }
356	    }
357	}
