506	pub trait Decode<Message> {
507	    type Error;
508	
509	    fn decode(self) -> Result<Message, Self::Error>;
510	}
511	
512	impl Decode<TransportMessage> for &mut RBatch {
513	    type Error = DidntRead;
514	
515	    fn decode(self) -> Result<TransportMessage, Self::Error> {
516	        let mut reader = self.buffer.reader();
517	        self.codec.read(&mut reader)
518	    }
519	}
520	
521	impl Decode<(TransportMessage, BatchSize)> for &mut RBatch {
522	    type Error = DidntRead;
523	
524	    fn decode(self) -> Result<(TransportMessage, BatchSize), Self::Error> {
525	        let len = self.buffer.len() as BatchSize;
526	        let mut reader = self.buffer.reader();
527	        let msg = self.codec.read(&mut reader)?;
528	        let end = self.buffer.len() as BatchSize;
529	        Ok((msg, len - end))
530	    }
531	}
532	
533	impl<'a> Decode<FrameReader<'a, ZSlice>> for &'a mut RBatch {
534	    type Error = DidntRead;
535	
536	    fn decode(self) -> Result<FrameReader<'a, ZSlice>, Self::Error> {
537	        self.codec.read(&mut self.buffer)
538	    }
539	}
