558	    #[test]
559	    fn rw_batch() {
560	        let mut rng = rand::thread_rng();
561	
562	        for _ in 0..1_000 {
563	            let msg_ins: [TransportMessage; 2] = [TransportMessage::rand(), {
564	                let mut msg_in = Fragment::rand();
565	                msg_in.payload = vec![0u8; rng.gen_range(8..1_024)].into();
566	                msg_in.into()
567	            }];
568	            for msg_in in msg_ins {
569	                let config = BatchConfig {
570	                    mtu: BatchSize::MAX,
571	                    is_streamed: rng.gen_bool(0.5),
572	                    #[cfg(feature = "transport_compression")]
573	                    is_compression: rng.gen_bool(0.5),
574	                };
575	                let mut wbatch = WBatch::new(config);
576	                wbatch.encode(&msg_in).unwrap();
577	                println!("Encoded WBatch: {wbatch:?}");
578	
579	                let mut buffer = zcondfeat!(
580	                    "transport_compression",
581	                    config.is_compression.then_some(BBuf::with_capacity(
582	                        lz4_flex::block::get_maximum_output_size(wbatch.as_slice().len()),
583	                    )),
584	                    None
585	                );
586	
587	                let res = wbatch.finalize(buffer.as_mut()).unwrap();
588	                let bytes = match res {
589	                    Finalize::Batch => wbatch.as_slice(),
590	                    Finalize::Buffer => buffer.as_mut().unwrap().as_slice(),
591	                };
592	                println!("Finalized WBatch: {bytes:02x?}");
593	
594	                let mut rbatch = RBatch::new(config, bytes.to_vec().into_boxed_slice());
595	                println!("Decoded RBatch: {rbatch:?}");
596	                rbatch
597	                    .initialize(|| {
598	                        zenoh_buffers::vec::uninit(config.mtu as usize).into_boxed_slice()
599	                    })
600	                    .unwrap();
601	                println!("Initialized RBatch: {rbatch:?}");
602	                let msg_out: TransportMessage = rbatch.decode().unwrap();
603	                assert_eq!(msg_in, msg_out);
604	            }
