14	use zenoh_protocol::{core::Bits, transport::TransportSn};
15	use zenoh_result::{bail, ZResult};
16	
17	const RES_U8: TransportSn = (u8::MAX >> 1) as TransportSn; // 1 byte max when encoded
18	const RES_U16: TransportSn = (u16::MAX >> 2) as TransportSn; // 2 bytes max when encoded
19	const RES_U32: TransportSn = (u32::MAX >> 4) as TransportSn; // 4 bytes max when encoded
20	const RES_U64: TransportSn = (u64::MAX >> 1) as TransportSn; // 9 bytes max when encoded
21	
22	pub(crate) fn get_mask(resolution: Bits) -> TransportSn {
23	    match resolution {
24	        Bits::U8 => RES_U8,
25	        Bits::U16 => RES_U16,
26	        Bits::U32 => RES_U32,
27	        Bits::U64 => RES_U64,
28	    }
29	}
30	
31	/// Sequence Number
32	///
33	/// Zenoh sequence numbers have a negotiable resolution. Each session can
34	/// ideally negotiate its resolution and use it across all priorities.
35	///
36	/// The [`SeqNum`][SeqNum] encapsulates the sequence numbers along with a
37	/// the comparison operators that check whether two sequence numbers are
38	/// less, equal or greater of each other.
39	///
40	#[derive(Clone, Copy, Debug)]
41	pub(crate) struct SeqNum {
42	    value: TransportSn,
43	    mask: TransportSn,
44	}
45	
46	impl SeqNum {
47	    /// Create a new sequence number with a given resolution.
48	    ///
49	    /// # Arguments
50	    /// * `value` - The sequence number.
51	    ///
52	    /// * `resolution` - The resolution (modulo) to be used for the sequence number.
53	    ///   As a consequence of wire zenoh's representation of sequence numbers it is
54	    ///   recommended that the resolution is a power of 2 with exponent multiple of 7.
55	    ///   Suggested values are:
56	    ///   - 256 (i.e., 2^7)
57	    ///   - 16_386 (i.e., 2^14)
58	    ///   - 2_097_152 (i.e., 2^21)
59	    ///
60	    /// # Errors
61	    ///
62	    /// This function will return an error if `value` is out of bound w.r.t. `resolution`. That is if
63	    /// `value` is greater or equal than `resolution`.
64	    ///
65	    pub(crate) fn make(value: TransportSn, resolution: Bits) -> ZResult<SeqNum> {
66	        let mask = get_mask(resolution);
67	        let mut sn = SeqNum { value: 0, mask };
68	        sn.set(value)?;
69	        Ok(sn)
70	    }
71	
72	    pub(crate) fn get(&self) -> TransportSn {
73	        self.value
74	    }
75	
76	    #[inline(always)]
77	    pub(crate) fn next(&self) -> TransportSn {
78	        self.value.wrapping_add(1) & self.mask
79	    }
80	
81	    #[inline(always)]
82	    pub(crate) fn resolution(&self) -> TransportSn {
83	        self.mask
84	    }
85	
86	    pub(crate) fn set(&mut self, value: TransportSn) -> ZResult<()> {
87	        if (value & !self.mask) != 0 {
88	            bail!("The sequence number value must be smaller than the resolution");
89	        }
90	
91	        self.value = value;
92	        Ok(())
93	    }
94	
95	    pub(crate) fn increment(&mut self) {
96	        self.value = self.next();
97	    }
98	
99	    /// Checks to see if two sequence number are in a precedence relationship,
100	    /// while taking into account roll backs.
101	    ///
102	    /// Two case are considered:
103	    ///
104	    /// ## Case 1: sna < snb
105	    ///
106	    /// In this case *sna* precedes *snb* iff (snb - sna) <= semi_int where
107	    /// semi_int is defined as half the sequence number resolution.
108	    /// In other terms, sna precedes snb iff there are less than half
109	    /// the length for the interval that separates them.
110	    ///
111	    /// ## Case 2: sna > snb
112	    ///
113	    /// In this case *sna* precedes *snb* iff (sna - snb) > semi_int.
114	    ///
115	    /// # Arguments
116	    ///
117	    /// * `value` -  The sequence number which should be checked for precedence relation.
118	    pub(crate) fn precedes(&self, value: TransportSn) -> ZResult<bool> {
119	        if (value & !self.mask) != 0 {
120	            bail!("The sequence number value must be smaller than the resolution");
121	        }
122	        let gap = value.wrapping_sub(self.value) & self.mask;
123	        Ok((gap != 0) && ((gap & !(self.mask >> 1)) == 0))
124	    }
