126	    /// Checks to see if two sequence number are in a precedence relationship,
127	    /// while taking into account roll backs AND do update the sn value if check succeed.
128	    ///
129	    /// Two case are considered:
130	    ///
131	    /// ## Case 1: sna < snb
132	    ///
133	    /// In this case *sna* precedes *snb* iff (snb - sna) <= semi_int where
134	    /// semi_int is defined as half the sequence number resolution.
135	    /// In other terms, sna precedes snb iff there are less than half
136	    /// the length for the interval that separates them.
137	    ///
138	    /// ## Case 2: sna > snb
139	    ///
140	    /// In this case *sna* precedes *snb* iff (sna - snb) > semi_int.
141	    ///
142	    /// # Arguments
143	    ///
144	    /// * `value` -  The sequence number which should be checked for precedence relation.
145	    pub(crate) fn roll(&mut self, value: TransportSn) -> ZResult<bool> {
146	        if (value & !self.mask) != 0 {
147	            bail!("The sequence number value must be smaller than the resolution");
148	        }
149	        let gap = value.wrapping_sub(self.value) & self.mask;
150	        if (gap != 0) && ((gap & !(self.mask >> 1)) == 0) {
151	            self.value = value;
152	            return Ok(true);
153	        }
154	        Ok(false)
155	    }
