157	    /// Computes the modulo gap between two sequence numbers.
158	    #[cfg(test)] // @TODO: remove #[cfg(test)] once reliability is implemented
159	    pub(crate) fn gap(&self, value: TransportSn) -> ZResult<TransportSn> {
160	        if (value & !self.mask) != 0 {
161	            bail!("The sequence number value must be smaller than the resolution");
162	        }
163	        Ok(value.wrapping_sub(self.value) & self.mask)
164	    }
