535	#[derive(Clone)]
536	struct Backoff {
537	    threshold: MicroSeconds,
538	    last_bytes: BatchSize,
539	    atomic: Arc<AtomicBackoff>,
540	    // active: bool,
541	}
542	
543	impl Backoff {
544	    fn new(threshold: Duration, atomic: Arc<AtomicBackoff>) -> Self {
545	        Self {
