554	// Inner structure to link the final stage with the initial stage of the pipeline
555	struct StageOutIn {
556	    s_out_r: RingBufferReader<BoxedWBatch, RBLEN>,
557	    current: Arc<Mutex<Current>>,
558	    backoff: Backoff,
559	}
560	
561	impl StageOutIn {
562	    #[inline]
563	    fn try_pull(&mut self) -> Pull {
564	        if let Some(batch) = self.s_out_r.pull() {
565	            self.backoff.atomic.active.store(false, Ordering::Relaxed);
566	            return Pull::Some(batch);
567	        }
568	
569	        self.try_pull_deep()
570	    }
571	
572	    fn try_pull_deep(&mut self) -> Pull {
573	        // Verify first backoff is not active
574	        let mut pull = !self.backoff.atomic.active.load(Ordering::Relaxed);
575	
576	        // If backoff is active, verify the current number of bytes is equal to the old number
577	        // of bytes seen in the previous backoff iteration
578	        if !pull {
579	            let new_bytes = self.backoff.atomic.bytes.load(Ordering::Relaxed);
580	            let old_bytes = self.backoff.last_bytes;
581	            self.backoff.last_bytes = new_bytes;
582	
583	            pull = new_bytes == old_bytes;
584	        }
585	
586	        // Verify that we have not been doing backoff for too long
587	        let mut backoff = 0;
588	        if !pull {
589	            let diff = (LOCAL_EPOCH.elapsed().as_micros() as MicroSeconds)
590	                .saturating_sub(self.backoff.atomic.first_write.load(Ordering::Relaxed));
591	
592	            if diff >= self.backoff.threshold {
593	                pull = true;
594	            } else {
595	                backoff = self.backoff.threshold - diff;
596	            }
597	        }
598	
599	        if pull {
600	            // It seems no new bytes have been written on the batch, try to pull
601	            if let Ok(mut g) = self.current.try_lock() {
602	                self.backoff.atomic.active.store(false, Ordering::Relaxed);
603	
604	                // First try to pull from stage OUT to make sure we are not in the case
605	                // where new_bytes == old_bytes are because of two identical serializations
606	                if let Some(batch) = self.s_out_r.pull() {
607	                    return Pull::Some(batch);
608	                }
609	
610	                // An incomplete (non-empty) batch may be available in the state IN pipeline.
611	                g.reset_pending();
612	                match g.batch.take() {
613	                    Some(batch) => {
614	                        return Pull::Some(batch);
615	                    }
616	                    None => {
617	                        return Pull::None;
618	                    }
619	                }
620	            }
621	        }
622	
623	        // Activate backoff
624	        self.backoff.atomic.active.store(true, Ordering::Relaxed);
625	
626	        // Do backoff
627	        Pull::Backoff(backoff)
628	    }
629	}
