686	// A 2-stage transmission pipeline
687	pub(crate) struct TransmissionPipeline;
688	impl TransmissionPipeline {
689	    // A MPSC pipeline
690	    pub(crate) fn make(
691	        config: TransmissionPipelineConf,
692	        priority: &[TransportPriorityTx],
693	        link_supports_priority: bool,
694	    ) -> (TransmissionPipelineProducer, TransmissionPipelineConsumer) {
695	        let status = Arc::new(TransmissionPipelineStatus {
696	            disabled: AtomicBool::new(false),
697	            congested: AtomicU8::new(0),
698	            pending: AtomicU8::new(0),
699	            waits: Waits {
700	                wait_before_drop: config.wait_before_drop,
701	                max_wait_before_drop_fragments: config.max_wait_before_drop_fragments,
702	                wait_before_close: config.wait_before_close,
703	            },
704	        });
705	
706	        let mut stage_in = vec![];
707	        let mut stage_out = vec![];
708	
709	        let default_queue_size = [config.queue_size[Priority::DEFAULT as usize]];
710	        let size_iter = if priority.len() == 1 {
711	            default_queue_size.iter()
712	        } else {
713	            config.queue_size.iter()
714	        };
715	
716	        // Create the channel for notifying that new batches are in the out ring buffer
717	        // This is a MPSC channel
718	        let (n_out_w, n_out_r) = event::new();
719	
720	        for (prio, num) in size_iter.enumerate() {
721	            assert!(*num != 0 && *num <= RBLEN);
722	
723	            // Create the refill ring buffer
724	            // This is a SPSC ring buffer
725	            let (mut s_ref_w, s_ref_r) = RingBuffer::<BoxedWBatch, RBLEN>::init();
726	            let mut batch_allocs = 0;
727	            if *config.queue_alloc.mode() == QueueAllocMode::Init {
728	                // Fill the refill ring buffer with batches
729	                for _ in 0..*num {
730	                    let batch = Box::new(WBatch::new(config.batch));
731	                    batch_allocs += 1;
732	                    assert!(s_ref_w.push(batch).is_none());
733	                }
734	            }
735	            // Create the channel for notifying that new batches are in the refill ring buffer
736	            // This is a SPSC channel
737	            let (n_ref_w, n_ref_r) = event::new();
738	            // If link supports priority, use per priority channel to notify for new batches
739	            let (n_out_w, n_out_r) = if link_supports_priority {
740	                event::new()
741	            } else {
742	                (n_out_w.clone(), n_out_r.clone())
743	            };
744	
745	            // Create the refill ring buffer
746	            // This is a SPSC ring buffer
747	            let (s_out_w, s_out_r) = RingBuffer::<BoxedWBatch, RBLEN>::init();
748	            let current = Arc::new(Mutex::new(Current {
749	                batch: None,
750	                status: status.clone(),
751	                prioflag: 1 << (prio as u8),
752	            }));
753	            let bytes = Arc::new(AtomicBackoff {
754	                active: CachePadded::new(AtomicBool::new(false)),
755	                bytes: CachePadded::new(AtomicBatchSize::new(0)),
756	                first_write: CachePadded::new(AtomicMicroSeconds::new(
757	                    LOCAL_EPOCH.elapsed().as_micros() as MicroSeconds,
758	                )),
759	            });
760	
761	            stage_in.push(Mutex::new(StageIn {
762	                s_ref: StageInRefill {
763	                    n_ref_r,
764	                    s_ref_r,
765	                    batch_config: (*num, config.batch),
766	                    batch_allocs,
767	                },
768	                s_out: StageInOut {
769	                    n_out_w: n_out_w.clone(),
770	                    s_out_w,
771	                    atomic_backoff: bytes.clone(),
772	                },
773	                mutex: StageInMutex {
774	                    current: current.clone(),
775	                    priority: priority[prio].clone(),
776	                },
777	                fragbuf: ZBuf::empty(),
778	                batching: config.batching_enabled,
779	                batch_config: config.batch,
780	            }));
781	
782	            // The stage out for this priority
783	            stage_out.push(StageOut {
784	                s_in: StageOutIn {
785	                    s_out_r,
786	                    current,
787	                    backoff: Backoff::new(config.batching_time_limit, bytes),
788	                },
789	                s_ref: StageOutRefill { n_ref_w, s_ref_w },
790	                n_out_r,
791	            });
792	        }
793	
794	        let producer = TransmissionPipelineProducer {
795	            stage_in: stage_in.into_boxed_slice().into(),
796	            status: status.clone(),
797	        };
798	        let consumer = TransmissionPipelineConsumer {
799	            stage_out: stage_out.into_boxed_slice(),
800	            n_out_r: (!link_supports_priority).then_some(n_out_r),
801	            status,
802	        };
803	
804	        (producer, consumer)
805	    }
806	}
