808	struct TransmissionPipelineStatus {
809	    // The whole pipeline is enabled or disabled
810	    disabled: AtomicBool,
811	    // Bitflags to indicate the given priority queue is congested
812	    congested: AtomicU8,
813	    // Bitflags to indicate the given priority queue has messages waiting to be sent
814	    pending: AtomicU8,
815	    // wait parameters
816	    // Note: this is placed here to optimize TransmissionPipelineProducer memory layout and improve performance
817	    waits: Waits,
818	}
819	
820	impl TransmissionPipelineStatus {
821	    fn set_disabled(&self, status: bool) {
822	        self.disabled.store(status, Ordering::Relaxed);
823	    }
824	
825	    fn is_disabled(&self) -> bool {
826	        self.disabled.load(Ordering::Relaxed)
827	    }
828	
829	    fn set_congested(&self, priority: Priority, status: bool) {
830	        let prioflag = 1 << priority as u8;
831	        if status {
832	            self.congested.fetch_or(prioflag, Ordering::Relaxed);
833	        } else {
834	            self.congested.fetch_and(!prioflag, Ordering::Relaxed);
835	        }
836	    }
837	
838	    fn is_congested(&self, priority: Priority) -> bool {
839	        let prioflag = 1 << priority as u8;
840	        self.congested.load(Ordering::Relaxed) & prioflag != 0
841	    }
842	
843	    fn get_pending(&self) -> Option<Priority> {
844	        let pending = self.pending.load(Ordering::Relaxed);
845	        let prio = pending.trailing_zeros();
846	        // Don't use try_from directly because it unfortunately returns a costly error
847	        if prio as usize >= Priority::NUM {
848	            return None;
849	        }
850	        Some(Priority::try_from(prio as u8).unwrap())
851	    }
852	}
