941	    pub(crate) fn disable(&self) {
942	        self.status.set_disabled(true);
943	
944	        // Acquire all the locks, in_guard first, out_guard later
945	        // Use the same locking order as in drain to avoid deadlocks
946	        let mut in_guards: Vec<MutexGuard<'_, StageIn>> =
947	            self.stage_in.iter().map(|x| zlock!(x)).collect();
948	
949	        // Unblock waiting pullers
950	        for ig in in_guards.iter_mut() {
951	            ig.s_out.notify(BatchSize::MAX);
952	        }
953	    }
