963	pub(crate) trait PipelineConsumer {
964	    #[allow(private_interfaces)]
965	    fn status(&self) -> &TransmissionPipelineStatus;
966	    fn stage_pull(&mut self) -> Result<(BoxedWBatch, Priority), Option<MicroSeconds>>;
967	    fn n_out_r(&self) -> &Waiter;
968	    async fn pull(&mut self) -> Option<(BoxedWBatch, Priority)> {
969	        while !self.status().is_disabled() {
970	            let backoff = match self.stage_pull() {
971	                Ok(res) => return Some(res),
972	                Err(b) => b,
973	            };
974	            // In case of writing many small messages, `recv_async()` will most likely return immediately.
975	            // While trying to pull from the queue, the stage_in `lock()` will most likely taken, leading to
976	            // a spinning behaviour while attempting to take the lock. Yield the current task to avoid
977	            // spinning the current task indefinitely.
978	            tokio::task::yield_now().await;
979	
980	            // Wait for the backoff to expire or for a new message
981	            let backoff_wait = match backoff {
982	                Some(b) => {
983	                    tokio::time::timeout(
984	                        Duration::from_micros(b as u64),
985	                        self.n_out_r().wait_async(),
986	                    )
987	                    .await
988	                }
989	                None => Ok(self.n_out_r().wait_async().await),
990	            };
991	            match backoff_wait {
992	                Ok(Ok(())) => {
993	                    // We have received a notification from the channel that some bytes are available, retry to pull.
994	                }
995	                Ok(Err(_channel_error)) => {
996	                    // The channel is closed, we can't be notified anymore. Break the loop and return None.
997	                    break;
998	                }
999	                Err(_timeout) => {
1000	                    // The backoff timeout expired. Be aware that tokio timeout may not sleep for short duration since
1001	                    // it has time resolution of 1ms: https://docs.rs/tokio/latest/tokio/time/fn.sleep.html
1002	                }
1003	            }
1004	        }
1005	        None
1006	    }
1007	    fn refill(&mut self, batch: BoxedWBatch, priority: Priority);
1008	    fn drain(&mut self) -> Vec<(BoxedWBatch, Priority)>;
1009	}
