1011	impl PipelineConsumer for TransmissionPipelineConsumer {
1012	    #[allow(private_interfaces)]
1013	    fn status(&self) -> &TransmissionPipelineStatus {
1014	        &self.status
1015	    }
1016	
1017	    fn stage_pull(&mut self) -> Result<(BoxedWBatch, Priority), Option<MicroSeconds>> {
1018	        while let Some(prio) = self.status.get_pending() {
1019	            let queue = &mut self.stage_out[prio as usize];
1020	            match queue.try_pull() {
1021	                Pull::Some(batch) => return Ok((batch, prio)),
1022	                Pull::Backoff(deadline) => return Err(Some(deadline)),
1023	                Pull::None => {}
1024	            }
1025	        }
1026	        Err(None)
1027	    }
1028	
1029	    fn n_out_r(&self) -> &Waiter {
1030	        self.n_out_r.as_ref().unwrap()
1031	    }
1032	
1033	    fn refill(&mut self, batch: BoxedWBatch, priority: Priority) {
1034	        if !batch.is_ephemeral() {
1035	            self.stage_out[priority as usize].refill(batch);
1036	            self.status.set_congested(priority, false);
1037	        }
1038	    }
1039	
1040	    fn drain(&mut self) -> Vec<(BoxedWBatch, Priority)> {
1041	        // Drain the remaining batches
1042	        let mut batches = vec![];
1043	
1044	        // Acquire all the locks, in_guard first, out_guard later
1045	        // Use the same locking order as in disable to avoid deadlocks
1046	        let locks = self
1047	            .stage_out
1048	            .iter()
1049	            .map(|x| x.s_in.current.clone())
1050	            .collect::<Vec<_>>();
1051	        let mut currents: Vec<_> = locks.iter().map(|x| zlock!(x)).collect::<Vec<_>>();
1052	
1053	        for (prio, s_out) in self.stage_out.iter_mut().enumerate() {
1054	            let mut bs = s_out.drain(&mut currents[prio]);
1055	            for b in bs.drain(..) {
1056	                batches.push((b, Priority::try_from(prio as u8).unwrap()));
1057	            }
1058	        }
1059	
1060	        batches
1061	    }
1062	}
