35	};
36	
37	/*************************************/
38	/*            TRANSPORT RX           */
39	/*************************************/
40	impl TransportUnicastUniversal {
41	    fn trigger_callback(
42	        &self,
43	        callback: &dyn TransportPeerEventHandler,
44	        #[allow(unused_mut)] // shared-memory feature requires mut
45	        mut msg: NetworkMessageMut,
46	        #[cfg(feature = "stats")] stats: &zenoh_stats::LinkStats,
47	    ) -> ZResult<()> {
48	        #[cfg(feature = "stats")]
49	        stats.inc_network_message(
50	            zenoh_stats::Rx,
51	            zenoh_protocol::network::NetworkMessageExt::as_ref(&msg),
52	        );
53	        #[cfg(feature = "shared-memory")]
54	        {
55	            if let Some(shm_context) = &self.shm_context {
56	                if let Err(e) =
57	                    crate::shm::map_zmsg_to_shmbuf(msg.as_mut(), &shm_context.shm_reader)
58	                {
59	                    tracing::debug!("Error receiving SHM buffer: {e}");
60	                    return Ok(());
61	                }
62	            }
63	        }
64	        callback.handle_message(msg)
65	    }
66	
67	    fn handle_close(&self, link: &Link, _reason: u8, session: bool) -> ZResult<()> {
68	        // Delete and clean up
69	        let c_transport = self.clone();
70	        let c_link = link.clone();
71	        // Spawn a task to avoid a deadlock waiting for this same task
72	        // to finish in the link close() joining the rx handle
73	        zenoh_runtime::ZRuntime::Net.spawn(async move {
74	            if session {
75	                let _ = c_transport.delete().await;
76	            } else {
77	                let _ = c_transport.del_link(c_link).await;
78	            }
79	        });
80	
81	        Ok(())
82	    }
83	
84	    fn handle_frame(
85	        &self,
86	        frame: FrameReader<ZSlice>,
87	        #[cfg(feature = "stats")] stats: &zenoh_stats::LinkStats,
88	    ) -> ZResult<()> {
89	        let priority = frame.ext_qos.priority();
90	        let c = if self.is_qos() {
91	            &self.priority_rx[priority as usize]
92	        } else if priority == Priority::DEFAULT {
93	            &self.priority_rx[0]
94	        } else {
95	            bail!(
96	                "Transport: {}. Unknown priority: {:?}.",
97	                self.config.zid,
98	                priority
99	            );
100	        };
101	
102	        let mut guard = match frame.reliability {
103	            Reliability::Reliable => zlock!(c.reliable),
104	            Reliability::BestEffort => zlock!(c.best_effort),
105	        };
106	
107	        if !self.verify_sn("Frame", frame.sn, &mut guard)? {
108	            // Drop invalid message and continue
109	            return Ok(());
110	        }
111	        if let Some(callback) = self.callback.get() {
112	            for mut msg in frame {
113	                self.trigger_callback(
114	                    callback.as_ref(),
115	                    msg.as_mut(),
116	                    #[cfg(feature = "stats")]
117	                    stats,
118	                )?;
119	            }
120	        } else {
121	            tracing::debug!(
122	                "Transport: {}. No callback available, dropping messages",
123	                self.config.zid,
124	            );
125	        }
126	
127	        Ok(())
128	    }
129	
130	    fn handle_fragment(
131	        &self,
132	        fragment: Fragment,
133	        #[cfg(feature = "stats")] stats: &zenoh_stats::LinkStats,
134	    ) -> ZResult<()> {
135	        let Fragment {
136	            reliability,
137	            more,
138	            sn,
139	            ext_qos: qos,
140	            ext_first,
141	            ext_drop,
142	            payload,
143	        } = fragment;
144	
145	        let c = if self.is_qos() {
146	            &self.priority_rx[qos.priority() as usize]
147	        } else if qos.priority() == Priority::DEFAULT {
148	            &self.priority_rx[0]
149	        } else {
150	            bail!(
151	                "Transport: {}. Unknown priority: {:?}.",
152	                self.config.zid,
153	                qos.priority()
154	            );
155	        };
156	
157	        let mut guard = match reliability {
158	            Reliability::Reliable => zlock!(c.reliable),
159	            Reliability::BestEffort => zlock!(c.best_effort),
160	        };
161	
162	        if !self.verify_sn("Fragment", sn, &mut guard)? {
163	            // Drop invalid message and continue
164	            return Ok(());
165	        }
166	        if self.config.patch.has_fragmentation_markers() {
167	            if ext_first.is_some() {
168	                guard.defrag.clear();
169	            } else if guard.defrag.is_empty() {
170	                tracing::trace!(
171	                    "Transport: {}. First fragment received without start marker.",
172	                    self.manager.config.zid,
173	                );
174	                return Ok(());
175	            }
176	            if ext_drop.is_some() {
177	                guard.defrag.clear();
178	                return Ok(());
179	            }
180	        }
181	        if guard.defrag.is_empty() {
182	            let _ = guard.defrag.sync(sn);
183	        }
184	        if let Err(e) = guard.defrag.push(sn, payload) {
185	            // Defrag errors don't close transport
186	            tracing::trace!("{}", e);
187	            return Ok(());
188	        }
189	        if !more {
190	            // When shared-memory feature is disabled, msg does not need to be mutable
191	            if let Some(mut msg) = guard.defrag.defragment() {
192	                if let Some(callback) = self.callback.get() {
193	                    return self.trigger_callback(
194	                        callback.as_ref(),
195	                        msg.as_mut(),
196	                        #[cfg(feature = "stats")]
197	                        stats,
198	                    );
199	                } else {
200	                    tracing::debug!(
201	                        "Transport: {}. No callback available, dropping messages: {:?}",
202	                        self.config.zid,
203	                        msg
204	                    );
205	                }
206	            } else {
207	                tracing::trace!("Transport: {}. Defragmentation error.", self.config.zid);
208	            }
209	        }
210	
211	        Ok(())
212	    }
213	
214	    fn verify_sn(
215	        &self,
216	        message_type: &str,
217	        sn: TransportSn,
218	        guard: &mut MutexGuard<'_, TransportChannelRx>,
219	    ) -> ZResult<bool> {
220	        let precedes = guard.sn.roll(sn)?;
221	        if !precedes {
